async function getDerivedKey() {
    // Generate a 256-bit key from the chrome.runtime.id
    const encoder = new TextEncoder();
    const idData = encoder.encode(chrome.runtime.id || 'smac-fallback-id');
    const hash = await crypto.subtle.digest('SHA-256', idData);
    return await crypto.subtle.importKey(
        'raw',
        hash,
        { name: 'AES-GCM' },
        false,
        ['encrypt', 'decrypt']
    );
}

async function encryptKey(plaintextKey) {
    if (!plaintextKey) return null;
    const key = await getDerivedKey();
    const iv = crypto.getRandomValues(new Uint8Array(12));
    const encoder = new TextEncoder();
    const data = encoder.encode(plaintextKey);
    const ciphertextBuffer = await crypto.subtle.encrypt(
        { name: 'AES-GCM', iv },
        key,
        data
    );

    // Store iv and ciphertext as base64
    const ivBase64 = btoa(String.fromCharCode(...iv));
    const ciphertextArray = new Uint8Array(ciphertextBuffer);
    const ciphertextBase64 = btoa(String.fromCharCode(...ciphertextArray));
    return { iv: ivBase64, ciphertext: ciphertextBase64 };
}

async function decryptKey(ivBase64, ciphertextBase64) {
    if (!ivBase64 || !ciphertextBase64) return null;
    const key = await getDerivedKey();

    const ivStr = atob(ivBase64);
    const iv = new Uint8Array(ivStr.length);
    for (let i = 0; i < ivStr.length; i++) iv[i] = ivStr.charCodeAt(i);

    const ciphertextStr = atob(ciphertextBase64);
    const ciphertext = new Uint8Array(ciphertextStr.length);
    for (let i = 0; i < ciphertextStr.length; i++) ciphertext[i] = ciphertextStr.charCodeAt(i);

    try {
        const decryptedBuffer = await crypto.subtle.decrypt(
            { name: 'AES-GCM', iv },
            key,
            ciphertext
        );
        const decoder = new TextDecoder();
        return decoder.decode(decryptedBuffer);
    } catch (e) {
        // We do not log the specific error to avoid leaking information
        return null;
    }
}

function cleanResponse(text) {
    if (!text) return 'SKIP';
    let cleaned = text.trim();
    if (cleaned.toUpperCase() === 'SKIP') return 'SKIP';

    cleaned = cleaned.replace(/```[\w]*\n?/g, '');
    cleaned = cleaned.replace(/```/g, '');
    cleaned = cleaned.replace(/`/g, '');
    cleaned = cleaned.replace(/^(Comment|Response|Reply|Output):\s*/i, '');
    cleaned = cleaned.replace(/[\s.,;:!"']*[Ss][Kk][Ii][Pp][\s.,;:!"']*$/g, '');
    cleaned = cleaned.replace(/\s+Skip\s*$/gi, '');
    cleaned = cleaned.replace(/\.\s*Skip\s*$/gi, '.');
    cleaned = cleaned.replace(/^Skip\s+/gi, '');
    cleaned = cleaned.replace(/^SKIP\s+/gi, '');
    cleaned = cleaned.trim();
    cleaned = cleaned.replace(/^["'"'"'`]+|["'"'"'`]+$/g, '');
    cleaned = cleaned.trim();

    if (!cleaned || cleaned.length < 5) return 'SKIP';
    return cleaned;
}

function buildPrompt(payload) {
    if (payload.mode === 'post') {
        return `You are a Senior Software Engineer with strong communication skills and a professional-yet-warm tone.

Post text: ${payload.text}
${payload.hasImage ? 'The post also contains an image (attached). Incorporate relevant visual details when they are genuinely useful.' : ''}

Task: Write a ${payload.intentLabel} comment. 2-4 sentences. Human and specific. No "Great post!" openers.

No markdown, no hashtags. Return ONLY the comment text.`;
    }

    if (payload.mode === 'profile') {
        return `You are a thoughtful professional who writes personalised outreach messages.

You have read the following profile information:
${payload.text}

Your task: Write a ${payload.intentLabel} outreach message to this person. It must:
