        const btn = createSmacButton(currentPlatform, !anchor && currentPlatform !== PLATFORMS.X);
        handleBtnClick(btn, () => handlePostClick(post, currentPlatform));

        if (currentPlatform === PLATFORMS.X) {
            post.style.position = 'relative';
