function detectPlatformFromHostname(hostname) {
    if (hostname.includes('twitter.com') || hostname === 'x.com' || hostname.endsWith('.x.com')) {
        return PLATFORMS.X;
    }
    if (hostname === 'linkedin.com' || hostname.endsWith('.linkedin.com')) {
        return PLATFORMS.LINKEDIN;
    }
    return null;
}

function detectModeFromUrl(rawUrl, providedPlatform = null) {
    if (!rawUrl) return null;

    let parsed;
    try {
        parsed = new URL(rawUrl);
    } catch {
        return null;
    }

    const platform = providedPlatform || detectPlatformFromHostname(parsed.hostname);
    if (!platform) return null;

    const path = parsed.pathname || '/';
    const segments = path.split('/').filter(Boolean);
    const firstSegment = segments[0] || '';

    if (platform === PLATFORMS.LINKEDIN) {
        if (path.startsWith('/messaging')) return MODES.MESSAGE;
        if (path.startsWith('/in/')) return MODES.PROFILE;
        if (path.startsWith('/feed') || path.startsWith('/posts/') || path.startsWith('/feed/update/')) {
            return MODES.POST;
        }
        return null;
    }

    if (path.startsWith('/messages')) return MODES.MESSAGE;
    if (
        path.startsWith('/home') ||
        path.startsWith('/explore') ||
        path.startsWith('/search') ||
        path.includes('/status/')
    ) {
        return MODES.POST;
    }
    if (segments.length === 1 && firstSegment && !X_RESERVED_PATHS.has(firstSegment)) {
        return MODES.PROFILE;
    }

    return null;
}

async function handleMessageClick(platform) {
    const config = SELECTORS[platform].message;
    const entries = Array.from(document.querySelectorAll(config.container)).slice(-30);
    const history = [];

    entries.forEach((entry) => {
        const bubble = entry.querySelector(config.text) || entry;
        const text = bubble?.innerText?.trim();
        if (!text) return;

        const isYou = detectSender(entry, bubble, platform);

        history.push(`${isYou ? 'You' : 'Them'}: ${text}`);
    });

    const isEmptyThread = history.length === 0;
    const intent = await showIntentModal('message', isEmptyThread);
    if (!intent) return null;

    const historyText = isEmptyThread
        ? 'No prior messages in this thread yet.'
        : history.join('\n');

    const response = await chrome.runtime.sendMessage({
        action: 'GENERATE_AI_RESPONSE',
        payload: {
            mode: 'message',
            intentLabel: intent,
            text: historyText,
            isEmptyThread
        }
    });

    if (response?.success) {
        return response.comment;
    }

    if (response?.error?.type === 'CORS') {
        throw { type: 'CORS', message: response.error.message };
    }

    throw new Error(response?.error || 'Unknown error from background worker.');
}

function detectSender(entry, bubble, platform) {
    const classNames = entry.className?.toString() || '';
    const entryStyle = window.getComputedStyle(entry);
    const bubbleStyle = bubble ? window.getComputedStyle(bubble) : null;

    if (platform === PLATFORMS.LINKEDIN) {
        return (
            classNames.includes('right') ||
            classNames.includes('sent') ||
            entryStyle.alignSelf === 'flex-end' ||
            entryStyle.justifyContent === 'flex-end' ||
            bubbleStyle?.alignSelf === 'flex-end'
        );
    }

    return (
        !!entry.querySelector('[data-testid="deleteMessageButton"]') ||
        entryStyle.alignSelf === 'flex-end' ||
        entryStyle.justifyContent === 'flex-end' ||
        bubbleStyle?.alignSelf === 'flex-end'
    );
}

async function handleProfileClick(platform) {
    const config = SELECTORS[platform].profile;
    let extractedText = '';

    if (platform === PLATFORMS.X) {
        const name = readText(config.userName);
        const bio = readText(config.bio);
        const header = readText(config.header);

        const tweetNodes = document.querySelectorAll(config.tweets);
        const tweets = Array.from(tweetNodes)
            .slice(0, 4)
            .map((tweet) => tweet.innerText?.trim())
            .filter(Boolean)
            .join('\n---\n');

        const sections = [];
        if (name) sections.push(`Name: ${name}`);
        if (bio) sections.push(`Bio: ${bio}`);
        if (header) sections.push(`Info: ${header}`);
        if (tweets) sections.push(`Recent Tweets:\n${tweets}`);
        extractedText = sections.join('\n');
    } else if (platform === PLATFORMS.LINKEDIN) {
        const name = readText(config.name);
        const headline = readText(config.headline);
        const about = readText(config.about);
        const featured = readText(config.featured);

        const expNodes = document.querySelectorAll(config.experience);
        const experience = Array.from(expNodes)
            .slice(0, 2)
            .map((entry) => entry.innerText?.trim())
            .filter(Boolean)
            .join('\n');

        const postNodes = document.querySelectorAll(config.posts);
        const posts = Array.from(postNodes)
            .slice(0, 4)
            .map((entry) => entry.innerText?.trim())
            .filter(Boolean)
            .join('\n---\n');

        const sections = [];
        if (name) sections.push(`Name: ${name}`);
        if (headline) sections.push(`Headline: ${headline}`);
        if (about) sections.push(`About: ${about}`);
        if (featured) sections.push(`Featured: ${featured}`);
        if (experience) sections.push(`Experience:\n${experience}`);
        if (posts) sections.push(`Recent Posts:\n${posts}`);
        extractedText = sections.join('\n');
    }

    if (!extractedText.trim()) {
        throw new Error('Could not extract profile information.');
    }

    // Limit to 3000 tokens roughly (approx 12000 chars)
    if (extractedText.length > 12000) {
        extractedText = extractedText.substring(0, 12000) + '...';
    }

    const intent = await showIntentModal('profile');
    if (!intent) return null;

    const response = await chrome.runtime.sendMessage({
        action: 'GENERATE_AI_RESPONSE',
        payload: {
            mode: 'profile',
            intentLabel: intent,
            text: extractedText
        }
    });

    if (response && response.success) {
        return response.comment;
    } else if (response?.error) {
        if (response.error.type === 'CORS') {
            throw { type: 'CORS', message: response.error.message };
        }
        throw new Error(response.error);
    }

    return null;
}

function readText(selector) {
    return document.querySelector(selector)?.innerText?.trim() || '';
}

async function handlePostClick(post, platform) {
    const s = SELECTORS[platform];
    let text = readFirstText(post, s.postText);

    if (!text) {
        // Last resort: get all text from post container, strip UI noise
        text = post.innerText
            .split('\n')
            .map(l => l.trim())
            .filter(l => l.length > 10) // remove short UI labels
            .filter(l => !['Like', 'Comment', 'Repost', 'Send', 'React', 'Share'].includes(l))
            .slice(0, 20)
            .join('\n');
    }

    if (!text) {
        throw new Error('Could not extract post text. Try clicking the button on a different post.');
    }

    const author = readFirstText(post, s.postAuthor);
    const hashtags = Array.from(new Set(text.match(/#[\p{L}\p{N}_-]+/gu) || []));
    const imageAltText = Array.from(post.querySelectorAll(s.postImage.join(', ')))
        .map((image) => image.getAttribute('alt')?.trim() || image.getAttribute('aria-label')?.trim() || '')
        .filter(Boolean);

    const extractedSections = [];
    if (author) extractedSections.push(`Author: ${author}`);
    extractedSections.push(`Post text: ${text}`);
    if (hashtags.length > 0) extractedSections.push(`Hashtags: ${hashtags.join(', ')}`);
    if (imageAltText.length > 0) extractedSections.push(`Image alt text: ${imageAltText.join(' | ')}`);

    const intent = await showIntentModal('post');
    if (!intent) return null; // Cancelled

    // Get coordinates for screenshot
    const rect = post.getBoundingClientRect();
    const coords = {
        x: rect.left,
        y: rect.top,
        width: rect.width,
        height: rect.height,
        dpr: window.devicePixelRatio || 1
    };

    const response = await chrome.runtime.sendMessage({
        action: 'GENERATE_AI_RESPONSE',
        payload: {
            mode: 'post',
            intentLabel: intent,
            text: extractedSections.join('\n'),
            coords
        }
    });

    if (response && response.success) {
        return response.comment;
    } else if (response?.error) {
        if (response.error.type === 'CORS') {
            throw { type: 'CORS', message: response.error.message };
        }
        throw new Error(response.error);
    }

    return null;
}

function readFirstText(parent, selectors = []) {
    for (const selector of selectors || []) {
        const el = parent.querySelector(selector);
        const value = el?.innerText?.trim();
        if (value) return value;
    }
    return '';
}

async function runRemote(apiKey, endpoint, model, promptText, imageBase64) {
    if (!endpoint || !endpoint.startsWith('https://')) {
        throw createBackendError('HTTPS_REQUIRED', 'Endpoint must use HTTPS');
    }

    if (!model) {
        throw createBackendError('CONFIG', 'Please enter a remote model name in the popup.');
    }

    // NATIVE GEMINI API SUPPORT
    if (endpoint.includes('generativelanguage.googleapis.com') && !endpoint.includes('/chat/completions')) {
        let baseUrl = endpoint.replace(/\/$/, '');
        if (!baseUrl.includes(':generateContent')) {
            if (baseUrl.endsWith('/v1beta') || baseUrl.endsWith('/v1')) {
                baseUrl = `${baseUrl}/models/${model}:generateContent`;
            } else {
                baseUrl = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent`;
            }
        }

        const parts = [{ text: promptText }];
        if (imageBase64) {
            parts.push({
                inlineData: {
                    mimeType: 'image/jpeg',
                    data: imageBase64
                }
            });
        }

        const response = await fetch(`${baseUrl}?key=${apiKey}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ contents: [{ parts }] })
        });

        if (!response.ok) {
            throw mapRemoteError(response.status, true);
        }

        const data = await response.json();
        return data.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || '';
    }

    // OPENAI COMPATIBLE API SUPPORT (Default)
    let messages = [{
        role: 'user',
        content: []
    }];

    messages[0].content.push({
        type: 'text',
        text: promptText
    });

    if (imageBase64) {
        messages[0].content.push({
            type: 'image_url',
            image_url: {
                url: `data:image/jpeg;base64,${imageBase64}`
            }
        });
    }

    const response = await fetch(endpoint, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify({
            model,
            messages: messages,
            stream: false
        })
    });

    if (!response.ok) {
        throw mapRemoteError(response.status, false);
    }

    const data = await response.json();
    return data.choices?.[0]?.message?.content?.trim() || '';
}

function mapRemoteError(status, isGemini) {
    if (status === 401 || status === 403) {
        return createBackendError('REMOTE_AUTH', `${isGemini ? 'Gemini API Error' : 'Remote API Error'} (${status}). Check your API key.`);
    }

    if (status === 429) {
        return createBackendError('REMOTE_RATE_LIMIT', 'API rate limit hit. Try again shortly.');
    }

    return createBackendError(
        'REMOTE_ERROR',
        `${isGemini ? 'Gemini API Error' : 'Remote API Error'} (${status}). Check your API key and endpoint.`
    );
}

function createBackendError(code, message) {
    const error = new Error(message);
    error.code = code;
    return error;
}

async function runOllama(model, promptText, imageBase64) {
    const endpoint = 'http://localhost:11434/api/generate';
    const selectedModel = typeof model === 'string' ? model.trim() : '';

    if (!selectedModel) {
        throw createBackendError('CONFIG', 'No local model configured. Open the SMAC popup and enter a model name.');
    }

    const body = {
        model: selectedModel,
        prompt: promptText,
        stream: false,
        options: { num_ctx: 4096 }
    };

    if (imageBase64) {
        body.images = [imageBase64];
    }

    let response;
    try {
        response = await fetch(endpoint, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(body),
        });
    } catch (networkErr) {
        throw createBackendError('OLLAMA_UNREACHABLE', 'Ollama unreachable. Is it running?');
    }

    if (response.status === 403) {
        throw createBackendError('CORS', 'Run ./start-smac.sh and fully reopen the LinkedIn or X tab.');
    }

    if (response.status === 404) {
        throw createBackendError('MODEL_NOT_FOUND', `Model "${selectedModel}" not found. Run: ollama pull ${selectedModel}`);
    }

    if (!response.ok) {
        throw createBackendError('OLLAMA_ERROR', `Ollama error (${response.status}). Check Ollama logs.`);
    }

    const data = await response.json();
    return data.response?.trim() || '';
}

function createBackendError(code, message) {
    const error = new Error(message);
    error.code = code;
    return error;
}
